// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ImpermanentLossCalculator {
    uint256 constant PRECISION = 1e18;

    // Returns IL in basis points (e.g., 570 = 5.70%)
    // priceRatioX18: final price / initial price, scaled by 1e18
    // Example: price doubled = 2e18, price halved = 0.5e18
    function calculateIL(uint256 priceRatioX18)
        external
        pure
        returns (uint256 ilBasisPoints)
    {
        // IL = 2 * sqrt(r) / (1 + r) - 1
        uint256 sqrtR = sqrt(priceRatioX18 * PRECISION);
        uint256 numerator = 2 * sqrtR;
        uint256 denominator = PRECISION + priceRatioX18;
        uint256 ratio = (numerator * PRECISION) / denominator;

        if (ratio >= PRECISION) {
            ilBasisPoints = 0;
        } else {
            ilBasisPoints = ((PRECISION - ratio) * 10_000) / PRECISION;
        }
    }

    function sqrt(uint256 x) internal pure returns (uint256 y) {
        if (x == 0) return 0;
        uint256 z = (x + 1) / 2;
        y = x;
        while (z < y) {
            y = z;
            z = (x / z + z) / 2;
        }
    }
}

