// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract HealthCheck {
    uint256 public constant LIQUIDATION_THRESHOLD = 80;
    uint256 public constant PRECISION = 1e18;

    struct Position {
        uint256 collateralAmount;
        uint256 debtAmount;
    }

    mapping(address => Position) public positions;

    function getHealthFactor(address user, uint256 collateralPrice)
        public
        view
        returns (uint256)
    {
        Position memory pos = positions[user];
        if (pos.debtAmount == 0) return type(uint256).max;

        uint256 collateralValue = (pos.collateralAmount * collateralPrice) / PRECISION;
        uint256 adjustedCollateral = (collateralValue * LIQUIDATION_THRESHOLD) / 100;
        return (adjustedCollateral * PRECISION) / pos.debtAmount;
    }

    function isLiquidatable(address user, uint256 collateralPrice)
        external
        view
        returns (bool)
    {
        return getHealthFactor(user, collateralPrice) < PRECISION;
    }
}

