// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";

contract MedianOracle {
    AggregatorV3Interface public feed1;
    AggregatorV3Interface public feed2;
    AggregatorV3Interface public feed3;
    uint256 public constant STALENESS = 3600;

    constructor(address _f1, address _f2, address _f3) {
        feed1 = AggregatorV3Interface(_f1);
        feed2 = AggregatorV3Interface(_f2);
        feed3 = AggregatorV3Interface(_f3);
    }

    function _getPrice(AggregatorV3Interface feed) internal view returns (uint256, bool) {
        try feed.latestRoundData() returns (
            uint80, int256 answer, uint256, uint256 updatedAt, uint80
        ) {
            if (answer <= 0 || block.timestamp - updatedAt > STALENESS) {
                return (0, false);
            }
            return (uint256(answer), true);
        } catch {
            return (0, false);
        }
    }

    function getMedianPrice() external view returns (uint256) {
        (uint256 p1, bool v1) = _getPrice(feed1);
        (uint256 p2, bool v2) = _getPrice(feed2);
        (uint256 p3, bool v3) = _getPrice(feed3);

        uint256 validCount = (v1 ? 1 : 0) + (v2 ? 1 : 0) + (v3 ? 1 : 0);
        require(validCount >= 2, "Too few valid feeds");

        if (validCount == 3) {
            // Sort and return median
            if (p1 > p2) (p1, p2) = (p2, p1);
            if (p2 > p3) (p2, p3) = (p3, p2);
            if (p1 > p2) (p1, p2) = (p2, p1);
            return p2;
        }

        // Two valid: return average
        if (v1 && v2) return (p1 + p2) / 2;
        if (v1 && v3) return (p1 + p3) / 2;
        return (p2 + p3) / 2;
    }
}

