// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

interface ILending {
    function repay(uint256 amount) external;
    function withdrawCollateral(uint256 amount) external;
    function getDebt(address user) external view returns (uint256);
    function getCollateral(address user) external view returns (uint256);
}

interface IDEX {
    function sellETH(uint256 ethAmount) external payable returns (uint256 usdcOut);
}

interface IPool {
    function flashLoanSimple(address receiver, address asset, uint256 amount, bytes calldata params, uint16 referralCode) external;
}

contract SelfLiquidator {
    IPool public immutable aavePool;
    ILending public immutable lending;
    IDEX public immutable dex;
    IERC20 public immutable usdc;
    address public owner;

    constructor(address _pool, address _lending, address _dex, address _usdc) {
        aavePool = IPool(_pool);
        lending = ILending(_lending);
        dex = IDEX(_dex);
        usdc = IERC20(_usdc);
        owner = msg.sender;
    }

    function selfLiquidate() external {
        require(msg.sender == owner, "Not owner");
        uint256 debt = lending.getDebt(address(this));
        aavePool.flashLoanSimple(address(this), address(usdc), debt, "", 0);
    }

    function executeOperation(
        address asset, uint256 amount, uint256 premium,
        address initiator, bytes calldata
    ) external returns (bool) {
        require(msg.sender == address(aavePool), "Invalid caller");
        require(initiator == address(this), "Invalid initiator");

        // 1. Repay debt
        usdc.approve(address(lending), amount);
        lending.repay(amount);

        // 2. Withdraw collateral
        uint256 collateral = lending.getCollateral(address(this));
        lending.withdrawCollateral(collateral);

        // 3. Sell enough ETH to cover loan + fee
        uint256 totalOwed = amount + premium;
        uint256 ethToSell = (collateral * totalOwed) / (totalOwed + 1e17);
        uint256 usdcReceived = dex.sellETH{value: ethToSell}(ethToSell);
        require(usdcReceived >= totalOwed, "Insufficient USDC");

        // 4. Approve repayment
        usdc.approve(address(aavePool), totalOwed);

        return true;
    }

    function withdraw() external {
        require(msg.sender == owner, "Not owner");
        payable(owner).transfer(address(this).balance);
    }

    receive() external payable {}
}

