// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract BoostedStaking {
    IERC20 public stakingToken;
    IERC20 public rewardsToken;

    struct StakeInfo {
        uint256 amount;
        uint256 lockEnd;
        uint256 multiplier;
    }

    mapping(address => StakeInfo) public stakes;
    uint256 public totalWeightedStake;
    uint256 public rewardRate;
    uint256 public lastUpdateTime;
    uint256 public rewardPerWeightedTokenStored;
    mapping(address => uint256) public userRewardPerWeightedTokenPaid;
    mapping(address => uint256) public rewards;

    constructor(address _staking, address _rewards) {
        stakingToken = IERC20(_staking);
        rewardsToken = IERC20(_rewards);
    }

    function getMultiplier(uint256 lockDays) public pure returns (uint256) {
        if (lockDays >= 90) return 20;
        if (lockDays >= 30) return 15;
        return 10;
    }

    function weightedBalance(address account) public view returns (uint256) {
        StakeInfo memory info = stakes[account];
        return (info.amount * info.multiplier) / 10;
    }

    modifier updateReward(address account) {
        rewardPerWeightedTokenStored = rewardPerWeightedToken();
        lastUpdateTime = block.timestamp;
        if (account != address(0)) {
            rewards[account] = earned(account);
            userRewardPerWeightedTokenPaid[account] = rewardPerWeightedTokenStored;
        }
        _;
    }

    function rewardPerWeightedToken() public view returns (uint256) {
        if (totalWeightedStake == 0) return rewardPerWeightedTokenStored;
        return rewardPerWeightedTokenStored +
            ((block.timestamp - lastUpdateTime) * rewardRate * 1e18 / totalWeightedStake);
    }

    function earned(address account) public view returns (uint256) {
        return (weightedBalance(account) *
            (rewardPerWeightedToken() - userRewardPerWeightedTokenPaid[account]) / 1e18)
            + rewards[account];
    }

    function stakeWithLock(uint256 amount, uint256 lockDays) external updateReward(msg.sender) {
        require(stakes[msg.sender].amount == 0, "Already staked");
        uint256 mult = getMultiplier(lockDays);
        stakes[msg.sender] = StakeInfo(amount, block.timestamp + lockDays * 1 days, mult);
        totalWeightedStake += (amount * mult) / 10;
        stakingToken.transferFrom(msg.sender, address(this), amount);
    }

    function withdraw() external updateReward(msg.sender) {
        StakeInfo memory info = stakes[msg.sender];
        require(info.amount > 0, "No stake");
        require(block.timestamp >= info.lockEnd, "Still locked");
        totalWeightedStake -= (info.amount * info.multiplier) / 10;
        delete stakes[msg.sender];
        stakingToken.transfer(msg.sender, info.amount);
    }

    function claimReward() external updateReward(msg.sender) {
        uint256 reward = rewards[msg.sender];
        if (reward > 0) {
            rewards[msg.sender] = 0;
            rewardsToken.transfer(msg.sender, reward);
        }
    }
}
